import fs from "node:fs";
import path from "node:path";
import { electron } from "./electron.js";

export function getProjectRootPath() {
  if (electron.app.isPackaged) {
    return electron.app.getAppPath();
  }

  return process.cwd();
}

export function resolveFromProjectRoot(...segments: string[]) {
  return path.join(getProjectRootPath(), ...segments);
}

export function getRuntimeStorageRoot() {
  if (electron.app.isPackaged) {
    const userDataRoot = electron.app.getPath("userData");
    const runtimeStorageRoot = path.join(userDataRoot, "runtime-data");
    fs.mkdirSync(runtimeStorageRoot, { recursive: true });
    return runtimeStorageRoot;
  }

  return resolveFromProjectRoot("runtime-data");
}

export function ensureRuntimeStorageRoot() {
  const runtimeStorageRoot = getRuntimeStorageRoot();
  fs.mkdirSync(runtimeStorageRoot, { recursive: true });
  return runtimeStorageRoot;
}

export function getVaultRegistryDirectory() {
  return path.join(ensureRuntimeStorageRoot(), "vault-manager");
}

export function getAppConfigDirectory() {
  const appConfigDirectory = path.join(ensureRuntimeStorageRoot(), "app");
  fs.mkdirSync(appConfigDirectory, { recursive: true });
  return appConfigDirectory;
}

export function getStartupSplashConfigPath() {
  return path.join(getAppConfigDirectory(), "startup-splash.json");
}

export function getVaultRegistryPath() {
  const vaultRegistryDirectory = getVaultRegistryDirectory();
  fs.mkdirSync(vaultRegistryDirectory, { recursive: true });
  return path.join(vaultRegistryDirectory, "vaults.json");
}

export function getVaultStartupThemeSnapshotPath(vaultBasePath: string) {
  return path.join(vaultBasePath, ".nexus", "startup-theme.json");
}

export function getNodeModulesPath() {
  return resolveFromProjectRoot("node_modules");
}
