import path from "node:path";
import { getCurrentVault } from "../../../shared/vault-state.js";
import { resolveItemLocation } from "./item-location.js";

function getVaultContentPath() {
  const contentPath = getCurrentVault()?.contentPath;
  return contentPath ? path.normalize(contentPath) : null;
}

function normalizeRelativePath(value: string | null | undefined) {
  if (value == null) {
    return value;
  }

  const normalized = path.normalize(value);
  if (normalized === ".") {
    return "";
  }

  return normalized.replace(/^[\\/]+/, "");
}

export function toVaultRelativePath(value: string | null | undefined) {
  if (value == null) {
    return value;
  }

  const contentPath = getVaultContentPath();
  const normalizedValue = path.normalize(value);

  if (!path.isAbsolute(normalizedValue) || !contentPath) {
    return normalizeRelativePath(normalizedValue);
  }

  return normalizeRelativePath(path.relative(contentPath, normalizedValue));
}

export function toVaultAbsolutePath(value: string | null | undefined) {
  if (value == null) {
    return value;
  }

  const normalizedValue = path.normalize(value);
  if (path.isAbsolute(normalizedValue)) {
    return normalizedValue;
  }

  const contentPath = getVaultContentPath();
  if (!contentPath) {
    return normalizedValue;
  }

  if (!normalizedValue || normalizedValue === ".") {
    return contentPath;
  }

  return path.join(contentPath, normalizedValue);
}

export function getStoredItemPath(item: any, fieldName = "path") {
  if (!item) {
    return null;
  }

  if (typeof item.getDataValue === "function") {
    return item.getDataValue(fieldName);
  }

  return item[fieldName] ?? null;
}

export function serializeVaultItem(item: any) {
  if (!item) {
    return item;
  }

  const plainItem =
    typeof item.get === "function"
      ? item.get({ plain: true })
      : { ...item };

  delete plainItem.repo;

  if ("path" in plainItem) {
    plainItem.path = toVaultAbsolutePath(
      getStoredItemPath(item, "path") ?? plainItem.path
    );
  }

  if (!("relative_path" in plainItem) && "path" in plainItem) {
    plainItem.relative_path = toVaultRelativePath(
      getStoredItemPath(item, "path") ?? plainItem.path
    );
  }

  if ("folder_note_path" in plainItem) {
    plainItem.folder_note_path = toVaultAbsolutePath(
      getStoredItemPath(item, "folder_note_path") ?? plainItem.folder_note_path
    );
  }

  if (!("relative_folder_note_path" in plainItem) && "folder_note_path" in plainItem) {
    plainItem.relative_folder_note_path = toVaultRelativePath(
      getStoredItemPath(item, "folder_note_path") ?? plainItem.folder_note_path
    );
  }

  if ("trashPath" in plainItem && plainItem.trashPath != null) {
    plainItem.trashPath = path.normalize(String(plainItem.trashPath));
  }

  return plainItem;
}

export async function serializeResolvedVaultItem(
  itemsRepository: { findById: (itemId: string) => Promise<any> },
  item: any,
) {
  const serialized = serializeVaultItem(item);

  if (!serialized?.id) {
    return serialized;
  }

  const location = await resolveItemLocation(itemsRepository, String(serialized.id));

  if (!location) {
    return serialized;
  }

  return {
    ...serialized,
    path: location.path,
    relative_path: location.relativePath,
    contentRelativePath: location.contentRelativePath,
  };
}

export async function serializeResolvedVaultItems(
  itemsRepository: { findById: (itemId: string) => Promise<any> },
  items: any[],
) {
  return Promise.all(
    (Array.isArray(items) ? items : []).map((item) => serializeResolvedVaultItem(itemsRepository, item)),
  );
}
